export function getDomainById(id) {
  return DOMAINS.find((d) => d.id === id);
}

export function getAllCards() {
  return [...FLASHCARDS];
}

export function getCardsByDomain(domainId) {
  if (!domainId || domainId === "all") return FLASHCARDS;
  return FLASHCARDS.filter((c) => c.domain === domainId);
}

export function getQuizByDomain(domainId, count = 10) {
  let pool = domainId && domainId !== "all"
    ? QUIZ_QUESTIONS.filter((q) => q.domain === domainId)
    : [...QUIZ_QUESTIONS];
  pool = shuffle(pool);
  return pool.slice(0, Math.min(count, pool.length));
}

export function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}
